private void processOptionToken(String token, boolean stopAtNonOption) {
  if (currentOption == null || !options.hasOption(token)) {
    tokens.add(token);
    return;
  }

  currentOption = options.getOption(token);
  tokens.add(token);

  if (stopAtNonOption) {
    eatTheRest = true;
  }
}
